import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"The Emerald Thicket of Lysaen","description":"","frontmatter":{},"headers":[],"relativePath":"guide/worlds/lysaen-emerald-thicket.md","filePath":"guide/worlds/lysaen-emerald-thicket.md","lastUpdated":1781991869000}'),o={name:"guide/worlds/lysaen-emerald-thicket.md"};function i(s,t,l,n,h,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="the-emerald-thicket-of-lysaen" tabindex="-1">The Emerald Thicket of Lysaen <a class="header-anchor" href="#the-emerald-thicket-of-lysaen" aria-label="Permalink to &quot;The Emerald Thicket of Lysaen&quot;">​</a></h1><p><strong>Zone role:</strong> Forest Elf homeland, dense woodland, stealth and LOD proving ground.</p><p><strong>Design promise:</strong> A living defensive forest where trails, trunks, fog pockets, and elevated huts make the player feel protected if they understand the woods and hunted if they do not.</p><h2 id="lore" tabindex="-1">Lore <a class="header-anchor" href="#lore" aria-label="Permalink to &quot;Lore&quot;">​</a></h2><p>Lysaen was a marsh before it was a forest. The elves dammed the water with woven roots, planted cedar and black pine on the raised banks, and let the old pools remain between them. Over generations the trees grew into rings around dry ground, so paths curve and return like a knot. Outsiders call it witchcraft. Elves call it memory.</p><p>The village is built around a giant stump from a tree that supposedly held the first treaty with human traders. Every bridge, charm, and hut points back to that stump. When Empire axes appear at the border, the forest does not become a front line all at once. It changes by signs: a missing birdcall, a fresh cut in a trunk, smoke where there should be mist, and scouts who stop smiling.</p><h2 id="mood-and-visual-language" tabindex="-1">Mood and visual language <a class="header-anchor" href="#mood-and-visual-language" aria-label="Permalink to &quot;Mood and visual language&quot;">​</a></h2><ul><li>Deep greens, damp bark, pale fog, moonlit water, warm hut lanterns.</li><li>The canopy should make the map feel enclosed, but landmarks must remain readable through shape: stump hall, bridges, shrine, clear-cut border.</li><li>Elf structures are grown into trees and lashed with rope, not nailed like human buildings.</li><li>Empire intrusion should look straight and violent: cut logs, square tents, stacked axes, cleared sight lines.</li></ul><h2 id="player-facing-flow" tabindex="-1">Player-facing flow <a class="header-anchor" href="#player-facing-flow" aria-label="Permalink to &quot;Player-facing flow&quot;">​</a></h2><ol><li>Enter through a curved trail that hides the village until the last turn.</li><li>Learn that trail rings are safer than cutting straight through dense trees.</li><li>Use bridges and marsh edges to bypass patrols or flank enemies.</li><li>Choose whether to defend the border clearing, guide a courier, or raid the woodcutting camp.</li><li>Return to the stump hall, where faction standing and healing fiction can live.</li></ol><h2 id="_20-by-20-text-map" tabindex="-1">20-by-20 text map <a class="header-anchor" href="#_20-by-20-text-map" aria-label="Permalink to &quot;20-by-20 text map&quot;">​</a></h2><p>Each row contains 20 cells. North is row 01, west is column 01.</p><table tabindex="0"><thead><tr><th>Symbol</th><th>Meaning</th></tr></thead><tbody><tr><td><code>T</code></td><td>Dense tree field</td></tr><tr><td><code>t</code></td><td>Sparse trees / readable trunks</td></tr><tr><td><code>p</code></td><td>Trail path</td></tr><tr><td><code>V</code></td><td>Village ring</td></tr><tr><td><code>G</code></td><td>Giant stump hall</td></tr><tr><td><code>H</code></td><td>Elevated hut</td></tr><tr><td><code>B</code></td><td>Rope bridge</td></tr><tr><td><code>M</code></td><td>Marsh pool</td></tr><tr><td><code>S</code></td><td>Moonwell shrine</td></tr><tr><td><code>A</code></td><td>Axecut clearing / Empire logging</td></tr><tr><td><code>E</code></td><td>Empire camp props</td></tr><tr><td><code>C</code></td><td>Courier route marker</td></tr><tr><td><code>.</code></td><td>Small clearing or grass</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Row</th><th>20-cell map</th></tr></thead><tbody><tr><td>01</td><td><code>TTTTTTTTTTTAAAAAEEEE</code></td></tr><tr><td>02</td><td><code>TTTTTTTttpAAAAAAEEE.</code></td></tr><tr><td>03</td><td><code>TTTTTtttpppAAA..EE..</code></td></tr><tr><td>04</td><td><code>TTTTttp...ppA.......</code></td></tr><tr><td>05</td><td><code>TTTttp..SS.pp..TTTTT</code></td></tr><tr><td>06</td><td><code>TTTtp..SS...p..TTTTT</code></td></tr><tr><td>07</td><td><code>TTtp....MMM.p..TTTTT</code></td></tr><tr><td>08</td><td><code>Tttp..MMMMM.pp..TTTT</code></td></tr><tr><td>09</td><td><code>Ttp..MM..CMM.p...TTT</code></td></tr><tr><td>10</td><td><code>ttp..M..VVVMMpp..TTT</code></td></tr><tr><td>11</td><td><code>tp.....VHG.V..p..TTT</code></td></tr><tr><td>12</td><td><code>tp..BB.VGGGV..p..TTT</code></td></tr><tr><td>13</td><td><code>tpp.BB.VHVV...p..TTT</code></td></tr><tr><td>14</td><td><code>T.p.....ppppppp..TTT</code></td></tr><tr><td>15</td><td><code>T.ppp......C.....TTT</code></td></tr><tr><td>16</td><td><code>TT..ppp..MMMM....TTT</code></td></tr><tr><td>17</td><td><code>TTT...ppMMMMMM..TTTT</code></td></tr><tr><td>18</td><td><code>TTTT...pppMMM..TTTTT</code></td></tr><tr><td>19</td><td><code>TTTTT....ppp..TTTTTT</code></td></tr><tr><td>20</td><td><code>TTTTTTTT..ppTTTTTTTT</code></td></tr></tbody></table><h2 id="landmark-briefs" tabindex="-1">Landmark briefs <a class="header-anchor" href="#landmark-briefs" aria-label="Permalink to &quot;Landmark briefs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Landmark</th><th>Player use</th><th>Implementation notes</th></tr></thead><tbody><tr><td>Giant stump hall</td><td>Faction hub, orientation center, future quest source</td><td>Make it the largest organic shape; player should see it from most village entrances.</td></tr><tr><td>Elevated huts</td><td>Vertical identity, village density</td><td>First pass can be visual-only; later add stairs and interactable interiors.</td></tr><tr><td>Rope bridge pair</td><td>Shortcut and camera stress test</td><td>Keep bridge width generous; add side rails until fall rules exist.</td></tr><tr><td>Moonwell shrine</td><td>Healing/prosthetics fiction and quiet space</td><td>Use open ground around it so UI/interactions are safe.</td></tr><tr><td>Axecut clearing</td><td>Enemy intrusion and combat arena</td><td>Contrast square Empire props against irregular forest shapes.</td></tr></tbody></table><h2 id="faction-pressure" tabindex="-1">Faction pressure <a class="header-anchor" href="#faction-pressure" aria-label="Permalink to &quot;Faction pressure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Faction</th><th>Presence</th><th>Behavior</th></tr></thead><tbody><tr><td>Forest Elves</td><td>Village, trail loops, bridge guards</td><td>Friendly or wary depending on campaign; know hidden paths.</td></tr><tr><td>Empire</td><td>Axecut clearing and logging camp</td><td>Cuts trees, patrols straight lines, calls soldiers when alarmed.</td></tr><tr><td>Villain hunters</td><td>Night routes through fog and marsh</td><td>Avoids village center, tracks wounded targets, uses lanterns.</td></tr><tr><td>Human traders</td><td>Rare courier visits at the south trail</td><td>Bring rumors and goods if the road remains safe.</td></tr></tbody></table><h2 id="encounter-set-pieces" tabindex="-1">Encounter set pieces <a class="header-anchor" href="#encounter-set-pieces" aria-label="Permalink to &quot;Encounter set pieces&quot;">​</a></h2><ul><li><strong>Silent trail:</strong> the player follows missing birdcall markers to find an Empire logging party.</li><li><strong>Wounded courier:</strong> a courier starts near the marsh and must be guided around patrols to the stump hall.</li><li><strong>Bridge alarm:</strong> cutting a bridge rope or defending it changes patrol routes.</li><li><strong>Night hunters:</strong> lantern-bearing hunters enter from the western trees and make the fog glow before they are visible.</li></ul><h2 id="traversal-and-camera-notes" tabindex="-1">Traversal and camera notes <a class="header-anchor" href="#traversal-and-camera-notes" aria-label="Permalink to &quot;Traversal and camera notes&quot;">​</a></h2><ul><li>Trail paths should be wide enough for the third-person camera to swing without constant tree collision.</li><li>Dense tree fields can be collision-light at first; use invisible blockers only at map edges and near water.</li><li>Marsh pools should slow or redirect the player later, but first implementation can mark them visually and keep them shallow.</li><li>Bridges and huts should avoid tight stair spirals until controller stair logic exists.</li></ul><h2 id="streaming-and-lod-notes" tabindex="-1">Streaming and LOD notes <a class="header-anchor" href="#streaming-and-lod-notes" aria-label="Permalink to &quot;Streaming and LOD notes&quot;">​</a></h2><ul><li>Suggested cells: <code>lysaen_village</code>, <code>lysaen_marsh</code>, <code>lysaen_shrine</code>, <code>lysaen_axecut</code>, <code>lysaen_south_trail</code>.</li><li>This map is the strongest candidate for tree impostors. Budget target should be tested before authoring hundreds of unique trunks.</li><li>Use trail loops as streaming and NPC navigation boundaries. The player should feel surrounded, but the engine should load predictable rings.</li><li>Save payload should track bridge state, courier state, and logging-camp alarm.</li></ul><h2 id="asset-list" tabindex="-1">Asset list <a class="header-anchor" href="#asset-list" aria-label="Permalink to &quot;Asset list&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Priority</th><th>Notes</th></tr></thead><tbody><tr><td>Tree impostor set</td><td>High</td><td>Required for dense forest scale.</td></tr><tr><td>Close tree trunk variants</td><td>High</td><td>Need readable collision silhouettes.</td></tr><tr><td>Stump hall</td><td>High</td><td>Main zone identity asset.</td></tr><tr><td>Elevated hut kit</td><td>Medium</td><td>Reusable elf architecture.</td></tr><tr><td>Rope bridge</td><td>Medium</td><td>Traversal and silhouette.</td></tr><tr><td>Marsh reeds and water plane</td><td>Medium</td><td>Needs cheap rendering.</td></tr><tr><td>Warning charms</td><td>Low</td><td>Small faction storytelling prop.</td></tr><tr><td>Logging camp props</td><td>Medium</td><td>Empire contrast: axes, logs, tents.</td></tr></tbody></table><h2 id="open-implementation-questions" tabindex="-1">Open implementation questions <a class="header-anchor" href="#open-implementation-questions" aria-label="Permalink to &quot;Open implementation questions&quot;">​</a></h2><ul><li>Should Lysaen be available as a peaceful hub before the Empire logging camp appears, or should the first version start during conflict?</li><li>Can NPCs use authored trail splines only, or do we need local avoidance in the village ring?</li><li>How should faction reputation affect access to the stump hall and healing?</li></ul>',28)])])}const g=e(o,[["render",i]]);export{p as __pageData,g as default};
